import { test, expect } from '@fixtures/test';
import { env } from '@utils/env';

test.describe('login @no-auth', () => {
  test.describe('Positive', () => {
    // Scenario 1: every available (non-locked) user logs in with valid
    // credentials and lands on the inventory page. Same flow, varying user →
    // one parameterized test (data-placement.md: login data stays inline).
    const validUsers = [
      'standard_user',
      'problem_user',
      'performance_glitch_user',
      'error_user',
      'visual_user',
    ];

    for (const user of validUsers) {
      // standard_user is the canonical auth gateway → @smoke. The other four
      // are the same flow under different valid accounts (configuration
      // variation per smoke-policy.md) → not smoke.
      const smoke = user === 'standard_user' ? '@smoke ' : '';
      test(`${smoke}${user} logs in successfully and lands on the inventory page`, async ({
        loginPage,
        page,
      }) => {
        await loginPage.goto();
        await loginPage.loginAs(user, env.password);
        await expect(page).toHaveURL(/\/inventory\.html$/);
      });
    }
  });

  test.describe('Negative', () => {
    // Scenarios 2–4: missing / invalid credentials are rejected with the exact
    // saucedemo error message. Same flow, varying inputs + expected error →
    // one parameterized test. The expected error strings are asserted behavior,
    // so they live in the spec, not in externalized data (data-placement.md).
    const invalidLoginCases = [
      {
        username: '',
        password: '',
        error: 'Epic sadface: Username is required',
        title: 'no credentials shows the username-required error',
      },
      {
        username: 'standard_user',
        password: '',
        error: 'Epic sadface: Password is required',
        title: 'missing password shows the password-required error',
      },
      {
        username: '',
        password: env.password,
        error: 'Epic sadface: Username is required',
        title: 'missing username shows the username-required error',
      },
      {
        username: 'invalid_user',
        password: 'wrong_password',
        error: 'Epic sadface: Username and password do not match any user in this service',
        title: 'invalid credentials shows the no-match error',
      },
    ];

    for (const { username, password, error, title } of invalidLoginCases) {
      test(title, async ({ loginPage }) => {
        await loginPage.goto();
        await loginPage.loginAs(username, password);
        await expect(loginPage.errorBanner).toBeVisible();
        expect(await loginPage.getErrorText()).toContain(error);
      });
    }
  });
  // Edge describe omitted — no edge tests for this issue.
});
